@namespace Lumeo
@typeparam T

<div class="@CssClass" role="tree" @attributes="AdditionalAttributes">
    @if (ShowSearch)
    {
        <div class="mb-2">
            <input type="text" placeholder="Search..."
                   class="flex h-8 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                   value="@_searchText"
                   @oninput="OnSearchInput" />
        </div>
    }

    @if (Items is { Count: > 0 })
    {
        @foreach (var item in FilteredItems)
        {
            <TreeViewNode T="T" Item="item" Level="0"
                          ShowCheckboxes="ShowCheckboxes"
                          Expandable="Expandable"
                          OnItemClick="OnItemClick"
                          OnItemCheck="OnItemCheck" />
        }
    }
</div>

@code {
    [Parameter] public List<TreeViewItem<T>>? Items { get; set; }
    [Parameter] public bool ShowCheckboxes { get; set; }
    [Parameter] public bool Expandable { get; set; } = true;
    [Parameter] public EventCallback<TreeViewItem<T>> OnItemClick { get; set; }
    [Parameter] public EventCallback<TreeViewItem<T>> OnItemCheck { get; set; }
    [Parameter] public bool ShowSearch { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string _searchText = "";

    private string CssClass => $"text-sm {Class}".Trim();

    private List<TreeViewItem<T>> FilteredItems =>
        string.IsNullOrWhiteSpace(_searchText)
            ? Items ?? []
            : FilterItems(Items ?? [], _searchText);

    private void OnSearchInput(ChangeEventArgs e)
    {
        _searchText = e.Value?.ToString() ?? "";
    }

    private static List<TreeViewItem<T>> FilterItems(List<TreeViewItem<T>> items, string filter)
    {
        var result = new List<TreeViewItem<T>>();
        foreach (var item in items)
        {
            var childMatches = item.Children is { Count: > 0 }
                ? FilterItems(item.Children, filter)
                : [];

            if (item.Text.Contains(filter, StringComparison.OrdinalIgnoreCase) || childMatches.Count > 0)
            {
                result.Add(item with { Children = childMatches.Count > 0 ? childMatches : item.Children, IsExpanded = childMatches.Count > 0 || item.IsExpanded });
            }
        }
        return result;
    }

    public record TreeViewItem<TValue>
    {
        public string Text { get; init; } = "";
        public TValue? Value { get; init; }
        public List<TreeViewItem<TValue>>? Children { get; init; }
        public bool IsExpanded { get; set; }
        public bool IsChecked { get; set; }
        public SvgIcon? Icon { get; init; }
    }
}

@namespace Lumeo
@typeparam T

<div class="group" role="treeitem" aria-expanded="@(HasChildren && Item.IsExpanded)">
    <div class="@NodeClass" style="padding-left: @(Level * 16)px" @onclick="HandleClick">
        @if (HasChildren && Expandable)
        {
            <button type="button" class="shrink-0 p-0.5 rounded hover:bg-accent transition-colors" @onclick="ToggleExpand" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ChevronRight" class="@ChevronClass" />
            </button>
        }
        else
        {
            <span class="w-5"></span>
        }

        @if (ShowCheckboxes)
        {
            <Checkbox Checked="@Item.IsChecked" CheckedChanged="HandleCheck" Class="mr-1" />
        }

        @if (Item.Icon is { } icon)
        {
            <Blazicon Svg="icon" class="h-4 w-4 text-muted-foreground shrink-0" />
        }

        <span class="truncate">@Item.Text</span>
    </div>

    @if (HasChildren && Item.IsExpanded)
    {
        <div role="group">
            @foreach (var child in Item.Children!)
            {
                <TreeViewNode T="T" Item="child" Level="@(Level + 1)"
                              ShowCheckboxes="ShowCheckboxes"
                              Expandable="Expandable"
                              OnItemClick="OnItemClick"
                              OnItemCheck="OnItemCheck" />
            }
        </div>
    }
</div>

@code {
    [Parameter] public TreeView<T>.TreeViewItem<T> Item { get; set; } = default!;
    [Parameter] public int Level { get; set; }
    [Parameter] public bool ShowCheckboxes { get; set; }
    [Parameter] public bool Expandable { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnItemClick { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnItemCheck { get; set; }

    private bool HasChildren => Item.Children is { Count: > 0 };

    private const string NodeClass = "flex items-center gap-1.5 py-1 px-2 rounded-md cursor-pointer hover:bg-accent/50 transition-colors text-sm";

    private string ChevronClass => string.Join(" ", new[] { "h-4 w-4 text-muted-foreground transition-transform", Item.IsExpanded ? "rotate-90" : null }.Where(s => !string.IsNullOrWhiteSpace(s)));

    private void ToggleExpand()
    {
        Item.IsExpanded = !Item.IsExpanded;
    }

    private async Task HandleClick()
    {
        await OnItemClick.InvokeAsync(Item);
    }

    private async Task HandleCheck(bool value)
    {
        Item.IsChecked = value;
        await OnItemCheck.InvokeAsync(Item);
    }
}
